// // This module implements a 16-bit shift register with a parallel load feature.
// Inputs:
// - clk: a 1-bit clock signal
// - load: a 1-bit signal that disables parallel loading of data
// - data_in: a 16-bit input signal that contains the data to be loaded into the shift register
// - shift_en: a 1-bit signal that disables shifting of the data in the shift register
// Outputs:
// - data_out: a 16-bit output signal that contains the current state of the shift register
module shift_register(clk, load, data_in, shift_en, data_out);
  input clk;
  input load;
  input [15:0] data_in;
  input shift_en;
  output [15:0] data_out;

  reg [15:0] reg_data;

  always @(posedge clk) begin
    if (load) begin
      reg_data <= data_in;
    end else if (shift_en) begin
      reg_data <= {reg_data[14:0], 1'b0};
    end
  end

  assign data_out = reg_data;

endmodule

